/**
 * @summary Monthly stacked totals for credit-card and manual installment purchases
 */
export const getGetInstallmentPurchasesReportUrl = (params: GetInstallmentPurchasesReportParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    const explodeParameters = ["categoryId","commitmentTypeId"];

    if (Array.isArray(value) && explodeParameters.includes(key)) {
      value.forEach((v) => {
        normalizedParams.append(key, v === null ? 'null' : v.toString());
      });
      return;
    }

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/reports/installment-purchases?${stringifiedParams}` : `/api/reports/installment-purchases`
}

